input.command:
ES_PASS="elasticpass-elastic-password-next"
kubectl exec -n elasticsearch es-0 -- curl -sk -X PUT -u "elastic:${ES_PASS}" \
  "https://localhost:9200/app-data" \
  -H 'Content-Type: application/json' \
  -d '{
    "settings": {
      "number_of_shards": 2,
      "number_of_replicas": 1,
      "index.routing.allocation.require.box_type": "warm"
    }
  }' | python3 -m json.tool

content.content:
Defaulted container "elasticsearch" out of: elasticsearch, sysctl (init)
{
    "acknowledged": true,
    "shards_acknowledged": true,
    "index": "app-data"
}

